CREATE TABLE IF NOT EXISTS "audit_logs" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "actor_user_id" bigint NULL,
  "actor_username" character varying NOT NULL DEFAULT '',
  "actor_display_name" character varying NOT NULL DEFAULT '',
  "action" character varying NOT NULL,
  "resource_type" character varying NOT NULL DEFAULT '',
  "resource_id" character varying NOT NULL DEFAULT '',
  "resource_name" character varying NOT NULL DEFAULT '',
  "success" boolean NOT NULL DEFAULT false,
  "request_id" character varying NOT NULL DEFAULT '',
  "ip" character varying NOT NULL DEFAULT '',
  "user_agent" character varying NOT NULL DEFAULT '',
  "message" character varying NOT NULL DEFAULT '',
  "metadata" jsonb NOT NULL DEFAULT '{}'::jsonb,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
CREATE INDEX IF NOT EXISTS "auditlog_created_at" ON "audit_logs" ("created_at");
CREATE INDEX IF NOT EXISTS "auditlog_action" ON "audit_logs" ("action");
CREATE INDEX IF NOT EXISTS "auditlog_actor_user_id" ON "audit_logs" ("actor_user_id");
CREATE INDEX IF NOT EXISTS "auditlog_request_id" ON "audit_logs" ("request_id");
CREATE INDEX IF NOT EXISTS "auditlog_resource_type" ON "audit_logs" ("resource_type");
CREATE INDEX IF NOT EXISTS "auditlog_success" ON "audit_logs" ("success");

CREATE TABLE IF NOT EXISTS "audit_policy_rules" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "source" character varying NOT NULL DEFAULT '',
  "enabled" boolean NOT NULL DEFAULT true,
  "priority" integer NOT NULL DEFAULT 100,
  "effect" character varying NOT NULL,
  "match_type" character varying NOT NULL DEFAULT 'exact',
  "method" character varying NOT NULL DEFAULT '',
  "path_pattern" character varying NOT NULL DEFAULT '',
  "event_type" character varying NOT NULL DEFAULT '',
  "risk_level" character varying NOT NULL DEFAULT '',
  "target_type" character varying NOT NULL DEFAULT '',
  "condition_expr" text NOT NULL DEFAULT '',
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  PRIMARY KEY ("id")
);
CREATE INDEX IF NOT EXISTS "audit_policy_rules_priority" ON "audit_policy_rules" ("priority", "id");
CREATE INDEX IF NOT EXISTS "audit_policy_rules_source" ON "audit_policy_rules" ("source");
CREATE INDEX IF NOT EXISTS "audit_policy_rules_event_type" ON "audit_policy_rules" ("event_type");
CREATE INDEX IF NOT EXISTS "audit_policy_rules_path_pattern" ON "audit_policy_rules" ("path_pattern");
CREATE UNIQUE INDEX IF NOT EXISTS "audit_policy_rules_name" ON "audit_policy_rules" ("name");

COMMENT ON TABLE "audit_logs" IS '审计日志表（审计模块）';
COMMENT ON COLUMN "audit_logs"."id" IS '主键 ID';
COMMENT ON COLUMN "audit_logs"."action" IS '审计动作标识';
COMMENT ON COLUMN "audit_logs"."resource_type" IS '资源类型';
COMMENT ON COLUMN "audit_logs"."resource_id" IS '资源 ID';
COMMENT ON COLUMN "audit_logs"."resource_name" IS '资源名称';
COMMENT ON COLUMN "audit_logs"."ip" IS '请求来源 IP 地址';
COMMENT ON COLUMN "audit_logs"."user_agent" IS '请求客户端标识';
COMMENT ON COLUMN "audit_logs"."success" IS '是否执行成功';
COMMENT ON COLUMN "audit_logs"."created_at" IS '创建时间';
COMMENT ON COLUMN "audit_logs"."actor_user_id" IS '操作人用户 ID，为空表示匿名或无法识别';
COMMENT ON COLUMN "audit_logs"."actor_username" IS '操作人用户名';
COMMENT ON COLUMN "audit_logs"."actor_display_name" IS '操作人显示名称';
COMMENT ON COLUMN "audit_logs"."message" IS '审计结果说明或错误信息';
COMMENT ON COLUMN "audit_logs"."request_id" IS '请求 ID';
COMMENT ON COLUMN "audit_logs"."metadata" IS '扩展审计元数据，使用 JSON 对象存储';

COMMENT ON TABLE "audit_policy_rules" IS '审计策略规则表（审计模块）';
COMMENT ON COLUMN "audit_policy_rules"."id" IS '主键 ID';
COMMENT ON COLUMN "audit_policy_rules"."name" IS '规则唯一名称';
COMMENT ON COLUMN "audit_policy_rules"."description" IS '规则说明';
COMMENT ON COLUMN "audit_policy_rules"."source" IS '规则来源类型，如请求、领域事件或安全事件';
COMMENT ON COLUMN "audit_policy_rules"."enabled" IS '规则是否启用';
COMMENT ON COLUMN "audit_policy_rules"."priority" IS '规则优先级，值越小越先匹配';
COMMENT ON COLUMN "audit_policy_rules"."effect" IS '规则生效方式，如纳入或排除审计';
COMMENT ON COLUMN "audit_policy_rules"."match_type" IS '路径或事件匹配方式，如精确或前缀';
COMMENT ON COLUMN "audit_policy_rules"."method" IS '匹配的 HTTP 方法，为空表示不限制';
COMMENT ON COLUMN "audit_policy_rules"."path_pattern" IS '匹配的请求路径或路径前缀';
COMMENT ON COLUMN "audit_policy_rules"."event_type" IS '匹配的领域事件或安全事件类型';
COMMENT ON COLUMN "audit_policy_rules"."risk_level" IS '命中的风险等级，为空表示不限制';
COMMENT ON COLUMN "audit_policy_rules"."target_type" IS '命中的目标资源类型，为空表示不限制';
COMMENT ON COLUMN "audit_policy_rules"."condition_expr" IS '扩展匹配条件表达式，为空表示无附加条件';
COMMENT ON COLUMN "audit_policy_rules"."created_at" IS '创建时间';
COMMENT ON COLUMN "audit_policy_rules"."updated_at" IS '最后更新时间';

